"use strict";(globalThis.webpackChunkgsf_docusaurus_template=globalThis.webpackChunkgsf_docusaurus_template||[]).push([[4585],{2383(e){e.exports=JSON.parse('{"tag":{"label":"role:cloud-engineer","permalink":"/tags/role-cloud-engineer","allTagsPath":"/tags","count":8,"items":[{"id":"architecture/system-topology/containerize-your-workload-where-applicable","title":"Containerize your workloads","description":"Containerizing workloads enables better resource utilisation and bin packing, reducing unnecessary compute allocation and embodied carbon compared to running full virtual machines.","permalink":"/architecture/system-topology/containerize-your-workload-where-applicable"},{"id":"requirements/encrypt-what-is-necessary","title":"Encrypt what is necessary","description":"Data protection through encryption is a crucial aspect of our security measures. However, the encryption process can be resource-intensive at multiple levels.","permalink":"/requirements/encrypt-what-is-necessary"},{"id":"architecture/system-topology/reduce-network-traversal-between-VMs","title":"Reduce network traversal between VMs","description":"Placing VMs in the same region or availability zone minimises the physical distance data must travel between instances, reducing the energy consumed by network traversal.","permalink":"/architecture/system-topology/reduce-network-traversal-between-VMs"},{"id":"operations/capacity-management/scale-kubernetes-workloads-based-on-events","title":"Scale Kubernetes workloads based on relevant demand metrics","description":"By default, Kubernetes scales workloads based on CPU and RAM utilization. In practice, however, it\'s difficult to correlate your application\'s demand drivers with CPU and RAM utilization. Scaling your workload based on relevant demand metrics that drive scaling of your applications, such as HTTP requests, queue length, and cloud alerting events can help reduce resource utilization, and therefore also your carbon emissions.","permalink":"/operations/capacity-management/scale-kubernetes-workloads-based-on-events"},{"id":"architecture/system-topology/scale-logical-components-independently","title":"Scale logical components independently","description":"Decomposing applications into independently scalable microservices allows each component to be right-sized for its own demand, reducing overall compute resource consumption and embodied carbon.","permalink":"/architecture/system-topology/scale-logical-components-independently"},{"id":"operations/scan-for-vulnerabilities","title":"Scan for vulnerabilities","description":"Many attacks on cloud infrastructure seek to misuse deployed resources, which leads to an unnecessary spike in usage and cost.","permalink":"/operations/scan-for-vulnerabilities"},{"id":"architecture/system-topology/evaluate-using-a-service-mesh","title":"Use a service mesh only if needed","description":"Service meshes add overhead through additional containers and increased network traffic, so they should only be deployed for applications that genuinely require the capabilities they provide.","permalink":"/architecture/system-topology/evaluate-using-a-service-mesh"},{"id":"architecture/technology-selection/use-energy-efficient-hardware","title":"Use cloud native processor VMs","description":"Cloud VMs built on energy-efficient processors, such as ARM-based cloud-native chips, can run scale-out workloads with significantly lower energy consumption and embodied carbon than traditional alternatives.","permalink":"/architecture/technology-selection/use-energy-efficient-hardware"}],"unlisted":false}}')}}]);